<?php
declare(strict_types=1);

require_once __DIR__ . '/../app/push_flows.php';
proteger_admin();
$pdo = getPDO();
push_flows_ensure_schema($pdo);

$canWrite = ($_SESSION['admin_tipo'] ?? 'principal') !== 'equipe';
if (!$canWrite) {
    $perms = json_decode((string)($_SESSION['equipe_perms'] ?? ''), true) ?: [];
    $canWrite = !empty($perms['notificacoes']['escrever']);
}
if (empty($_SESSION['push_admin_csrf'])) $_SESSION['push_admin_csrf'] = bin2hex(random_bytes(24));
$csrf = (string)$_SESSION['push_admin_csrf'];
$flowId = max(0, (int)($_GET['id'] ?? $_POST['flow_id'] ?? 0));
$flow = push_flow_find($pdo, $flowId);
if (!$flow) { http_response_code(404); exit('Fluxo não encontrado.'); }
$error = '';
$graph = push_flow_decode_graph((string)$flow['draft_graph_json']);

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    try {
        if (!$canWrite) throw new RuntimeException('Seu usuário não possui permissão de escrita.');
        if (!hash_equals($csrf, (string)($_POST['csrf'] ?? ''))) throw new RuntimeException('Sessão expirada. Recarregue a página.');
        $graph = push_flow_decode_graph((string)($_POST['graph_json'] ?? ''));
        $name = (string)($_POST['name'] ?? '');
        $description = (string)($_POST['description'] ?? '');
        $lockVersion = (int)($_POST['lock_version'] ?? 0);
        $admin = (string)($_SESSION['equipe_nome'] ?? 'Administrador');
        if (($_POST['action'] ?? '') === 'publish') {
            push_flow_publish($pdo, $flowId, $name, $description, $graph, $lockVersion, $admin);
        } else {
            push_flow_save($pdo, $flowId, $name, $description, $graph, $lockVersion, $admin);
        }
        header('Location: notificacoes.php?flow_saved=1');
        exit;
    } catch (Throwable $e) {
        $error = $e->getMessage();
        $flow['name'] = (string)($_POST['name'] ?? $flow['name']);
        $flow['description'] = (string)($_POST['description'] ?? $flow['description']);
    }
}

function pf_h($value): string { return htmlspecialchars((string)$value, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8'); }
$menu = 'notificacoes';
$page_title = 'Editor de fluxo push';
$triggerOptions = push_flow_trigger_options();
include __DIR__ . '/_header.php';
?>
