16px}.pf-zoom{min-width:52px!important;font-size:10px!important}.pf-inspector-empty{padding:28px 8px;color:var(--muted);font-size:11px;text-align:center;line-height:1.55}.pf-fields{display:grid;gap:11px}.pf-field label{display:block;margin-bottom:4px;color:var(--muted);font-size:9px;text-transform:uppercase;letter-spacing:.06em}.pf-field input,.pf-field select,.pf-field textarea{width:100%;border:1px solid var(--border);border-radius:8px;padding:8px 9px;background:var(--bg);color:var(--text);font:inherit;font-size:11px}.pf-field textarea{min-height:78px;resize:vertical}.pf-check{display:flex;align-items:flex-start;gap:7px;color:var(--text);font-size:10px}.pf-check input{width:auto;margin-top:2px}.pf-inspector-actions{display:flex;gap:7px;margin-top:15px;padding-top:12px;border-top:1px solid var(--border)}.pf-readonly{opacity:.65;pointer-events:none}@media(max-width:1100px){.pf-editor{grid-template-columns:160px minmax(360px,1fr) 270px}.pf-identity{grid-template-columns:1fr}.pf-top{align-items:flex-start}}@media(max-width:800px){.pf-editor{height:auto;min-height:0;grid-template-columns:1fr}.pf-palette{border-right:0;border-bottom:1px solid var(--border)}.pf-palette-list{grid-template-columns:repeat(3,1fr)}.pf-canvas{height:620px}.pf-inspector{border-left:0;border-top:1px solid var(--border)}.pf-top{flex-wrap:wrap}.pf-identity{order:3;flex-basis:100%}}
