<script>
(function(){
const canWrite=<?= $canWrite ? 'true' : 'false' ?>;
const triggerOptions=<?=json_encode($triggerOptions,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_HEX_TAG|JSON_HEX_AMP)?>;
let graph=<?=json_encode($graph,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES|JSON_HEX_TAG|JSON_HEX_AMP)?>;
if(!graph||!Array.isArray(graph.nodes)||!Array.isArray(graph.edges))graph={schemaVersion:1,nodes:[],edges:[],viewport:{x:80,y:60,zoom:1}};
const types={trigger:{label:'Gatilho inicial',color:'#38bdf8'},condition:{label:'Condição',color:'#10b981'},wait:{label:'Esperar',color:'#fb7185'},action:{label:'Ação de tag',color:'#f59e0b'},integration:{label:'Integração',color:'#a78bfa'},push:{label:'Notificação push',color:'#facc15'}};
const canvas=document.getElementById('pfCanvas'),viewport=document.getElementById('pfViewport'),nodesEl=document.getElementById('pfNodes'),edgesEl=document.getElementById('pfEdges'),inspector=document.getElementById('pfInspector');
let view=Object.assign({x:80,y:60,zoom:1},graph.viewport||{}),selected=null,pending=null,dragState=null,panState=null;
const uid=p=>(p+'_'+Date.now().toString(36)+'_'+Math.random().toString(36).slice(2,7));
const esc=v=>String(v??'').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
function defaultConfig(type){return {trigger:{label:'Início do fluxo',event:'INSCRITO'},condition:{label:'Nova condição',field:'tag',operator:'has',value:''},wait:{label:'Aguardar',duration:1,unit:'hours',limitWindow:false,windowStart:'08:00',windowEnd:'20:00'},action:{label:'Alterar tag',action:'add_tag',tag:''},integration:{label:'Enviar integração',provider:'webhook',target:'',payload:''},push:{label:'Enviar notificação',title:'',body:'',clickUrl:'trilha.php'}}[type]||{};}
function palette(){const el=document.getElementById('pfPalette');Object.entries(types).forEach(([type,meta])=>{const b=document.createElement('button');b.type='button';b.className='pf-palette-item';b.draggable=canWrite;b.style.setProperty('--type-color',meta.color);b.innerHTML='<span class="pf-dot"></span>'+esc(meta.label);b.addEventListener('dragstart',e=>e.dataTransfer.setData('application/x-push-node',type));b.addEventListener('click',()=>{if(!canWrite)return;addNode(type,220+graph.nodes.length*24,140+graph.nodes.length*18)});el.appendChild(b)});}
function summary(n){const c=n.config||{};if(n.type==='trigger')return triggerOptions[c.event]||c.event||'Escolha o evento';if(n.type==='condition')return (c.field||'campo')+' '+(c.operator||'')+' '+(c.value||'');if(n.type==='wait')return 'Aguardar '+(c.duration||1)+' '+({minutes:'minuto(s)',hours:'hora(s)',days:'dia(s)'}[c.unit]||'');if(n.type==='action')return (c.action==='remove_tag'?'Remover ':'Adicionar ')+(c.tag||'tag');if(n.type==='integration')return (c.provider||'Integração')+(c.target?' · '+c.target:'');if(n.type==='push')return c.title||'Configure a notificação';return '';}
function applyView(){view.zoom=Math.max(.35,Math.min(1.8,Number(view.zoom)||1));viewport.style.transform=`translate(${view.x}px,${view.y}px) scale(${view.zoom})`;document.getElementById('pfZoomLabel').textContent=Math.round(view.zoom*100)+'%';graph.viewport={x:view.x,y:view.y,zoom:view.zoom};}
function render(){nodesEl.innerHTML='';graph.nodes.forEach(n=>{const meta=types[n.type],el=document.createElement('div');el.className='pf-node'+(selected===n.id?' selected':'');el.dataset.id=n.id;el.style.cssText=`left:${Number(n.x)||0}px;top:${Number(n.y)||0}px;--type-color:${meta.color}`;el.innerHTML=`${n.type!=='trigger'?'<span class="pf-port in" data-port="in"></span>':''}<div class="pf-node-head"><span class="pf-dot"></span><strong>${esc(n.config?.label||meta.label)}</strong></div><div class="pf-node-body">${esc(summary(n))}</div>${n.type==='condition'?'<span class="pf-port-label yes">SIM</span><span class="pf-port out yes" data-port="out" data-handle="yes"></span><span class="pf-port-label no">NÃO</span><span class="pf-port out no" data-port="out" data-handle="no"></span>':'<span class="pf-port out" data-port="out" data-handle="default"></span>'}`;el.addEventListener('click',e=>{if(e.target.closest('.pf-port'))return;selected=n.id;render();renderInspector()});el.querySelector('.pf-node-head').addEventListener('pointerdown',e=>startNodeDrag(e,n));el.querySelectorAll('.pf-port').forEach(p=>p.addEventListener('click',e=>portClick(e,n,p)));nodesEl.appendChild(el)});requestAnimationFrame(renderEdges);applyView();}
function portClick(e,node,port){e.stopPropagation();if(!canWrite)return;if(port.dataset.port==='out'){pending={source:node.id,handle:port.dataset.handle||'default'};document.querySelectorAll('.pf-port.pending').forEach(x=>x.classList.remove('pending'));port.classList.add('pending');return}if(pending&&pending.source!==node.id){if(!graph.edges.some(x=>x.source===pending.source&&x.target===node.id&&x.sourceHandle===pending.handle)){graph.edges.push({id:uid('edge'),source:pending.source,target:node.id,sourceHandle:pending.handle})}pending=null;render();}}
function nodePoint(n,out,handle){const x=(Number(n.x)||0)+(out?210:0);let y=(Number(n.y)||0)+(out?80:40);if(out&&n.type==='condition')y=(Number(n.y)||0)+(handle==='yes'?58:84);return [x,y];}
function renderEdges(){edgesEl.innerHTML='';graph.edges.forEach(edge=>{const s=graph.nodes.find(n=>n.id===edge.source),t=graph.nodes.find(n=>n.id===edge.target);if(!s||!t)return;const [x1,y1]=nodePoint(s,true,edge.sourceHandle),[x2,y2]=nodePoint(t,false),bend=Math.max(55,Math.abs(x2-x1)*.45),d=`M ${x1} ${y1} C ${x1+bend} ${y1}, ${x2-bend} ${y2}, ${x2} ${y2}`,mx=(x1+x2)/2,my=(y1+y2)/2;const g=document.createElementNS('http://www.w3.org/2000/svg','g');g.setAttribute('class','pf-edge-group');g.innerHTML=`<path class="pf-edge-visible" d="${d}"/><path class="pf-edge-hit" d="${d}"/><g class="pf-edge-delete" transform="translate(${mx} ${my})"><circle r="10"></circle><text y="-1">×</text></g>`;g.querySelector('.pf-edge-delete').addEventListener('click',()=>{if(!canWrite)return;graph.edges=graph.edges.filter(x=>x.id!==edge.id);renderEdges()});edgesEl.appendChild(g)});}
function startNodeDrag(e,node){if(!canWrite||e.button!==0)return;e.preventDefault();selected=node.id;dragState={node,startX:e.clientX,startY:e.clientY,x:Number(node.x)||0,y:Number(node.y)||0};render();renderInspector();document.addEventListener('pointermove',moveNode);document.addEventListener('pointerup',endNode,{once:true});}
function moveNode(e){if(!dragState)return;dragState.node.x=Math.max(0,dragState.x+(e.clientX-dragState.startX)/view.zoom);dragState.node.y=Math.max(0,dragState.y+(e.clientY-dragState.startY)/view.zoom);const el=nodesEl.querySelector(`[data-id="${dragState.node.id}"]`);if(el){el.style.left=dragState.node.x+'px';el.style.top=dragState.node.y+'px'}renderEdges();}
function endNode(){dragState=null;document.removeEventListener('pointermove',moveNode);}
function addNode(type,x,y){if(type==='trigger'&&graph.nodes.some(n=>n.type==='trigger')){alert('O fluxo pode ter apenas um gatilho inicial.');return}const node={id:uid(type),type,x:Math.max(0,x),y:Math.max(0,y),config:defaultConfig(type)};graph.nodes.push(node);selected=node.id;render();renderInspector();}
function options(map,value){return Object.entries(map).map(([v,l])=>`<option value="${esc(v)}"${String(value)===v?' selected':''}>${esc(l)}</option>`).join('');}
function field(label,key,value,type='text',extra=''){return `<div class="pf-field"><label>${esc(label)}</label><input type="${type}" data-key="${esc(key)}" value="${esc(value)}" ${extra}></div>`;}
function selectField(label,key,value,map){return `<div class="pf-field"><label>${esc(label)}</label><select data-key="${esc(key)}">${options(map,value)}</select></div>`;}
function textarea(label,key,value){return `<div class="pf-field"><label>${esc(label)}</label><textarea data-key="${esc(key)}">${esc(value)}</textarea></div>`;}
function renderInspector(){const n=graph.nodes.find(x=>x.id===selected);if(!n){inspector.innerHTML='<div class="pf-inspector-empty">Selecione um bloco no canvas para configurar.</div>';return}const c=n.config||{},meta=types[n.type];let html=`<div class="pf-fields">${field('Nome do bloco','label',c.label||meta.label)}`;
if(n.type==='trigger')html+=selectField('Evento de início','event',c.event||'INSCRITO',triggerOptions)+field('Filtro de turma/curso (opcional)','filter',c.filter||'');
if(n.type==='condition')html+=selectField('Campo','field',c.field||'tag',{tag:'Tag',turma:'Turma inscrita',email:'E-mail'})+selectField('Operador','operator',c.operator||'has',{has:'Possui/contém',not_has:'Não possui/não contém',equals:'É igual',not_equals:'É diferente'})+field('Valor','value',c.value||'');
if(n.type==='wait'){html+=field('Duração','duration',c.duration||1,'number','min="1" max="525600"')+selectField('Unidade','unit',c.unit||'hours',{minutes:'Minutos',hours:'Horas',days:'Dias'})+`<label class="pf-check"><input type="checkbox" data-key="limitWindow" ${c.limitWindow?'checked':''}> Limitar horário para continuar</label>`+field('Horário inicial','windowStart',c.windowStart||'08:00','time')+field('Horário final','windowEnd',c.windowEnd||'20:00','time');}
if(n.type==='action')html+=selectField('Ação','action',c.action||'add_tag',{add_tag:'Adicionar tag',remove_tag:'Remover tag'})+field('Nome da tag','tag',c.tag||'');
if(n.type==='integration')html+=selectField('Integração','provider',c.provider||'webhook',{webhook:'Webhook',superfuncionario:'SuperFuncionário',manychat:'ManyChat'})+field('Destino/regra/fluxo','target',c.target||'')+textarea('Payload/variáveis','payload',c.payload||'');
if(n.type==='push')html+=field('Título','title',c.title||'','text','maxlength="150"')+textarea('Mensagem','body',c.body||'')+field('Link interno ao clicar','clickUrl',c.clickUrl||'trilha.php');
html+=`</div><div class="pf-inspector-actions"><button class="btn btn-danger btn-sm" type="button" id="pfDeleteNode">Excluir bloco</button></div>`;inspector.innerHTML=html;inspector.querySelectorAll('[data-key]').forEach(input=>input.addEventListener('input',()=>{c[input.dataset.key]=input.type==='checkbox'?input.checked:(input.type==='number'?Number(input.value):input.value);n.config=c;render()}));document.getElementById('pfDeleteNode').addEventListener('click',()=>{if(!canWrite)return;if(n.type==='trigger'&&!confirm('Excluir o gatilho inicial? O fluxo não poderá ser publicado até adicionar outro.'))return;graph.nodes=graph.nodes.filter(x=>x.id!==n.id);graph.edges=graph.edges.filter(x=>x.source!==n.id&&x.target!==n.id);selected=null;render();renderInspector()});}
canvas.addEventListener('dragover',e=>e.preventDefault());canvas.addEventListener('drop',e=>{e.preventDefault();const type=e.dataTransfer.getData('application/x-push-node');if(!types[type])return;const r=canvas.getBoundingClientRect();addNode(type,(e.clientX-r.left-view.x)/view.zoom,(e.clientY-r.top-view.y)/view.zoom)});
canvas.addEventListener('pointerdown',e=>{if(e.button!==0||e.target.closest('.pf-node,.pf-canvas-tools'))return;panState={x:e.clientX,y:e.clientY,vx:view.x,vy:view.y};canvas.setPointerCapture(e.pointerId)});canvas.addEventListener('pointermove',e=>{if(!panState)return;view.x=panState.vx+e.clientX-panState.x;view.y=panState.vy+e.clientY-panState.y;applyView()});canvas.addEventListener('pointerup',()=>panState=null);canvas.addEventListener('wheel',e=>{e.preventDefault();const old=view.zoom,delta=e.deltaY<0?1.1:.9,newZoom=Math.max(.35,Math.min(1.8,old*delta)),r=canvas.getBoundingClientRect(),cx=e.clientX-r.left,cy=e.clientY-r.top;view.x=cx-(cx-view.x)*(newZoom/old);view.y=cy-(cy-view.y)*(newZoom/old);view.zoom=newZoom;applyView()},{passive:false});
document.getElementById('pfZoomIn').onclick=()=>{view.zoom*=1.15;applyView()};document.getElementById('pfZoomOut').onclick=()=>{view.zoom*=.85;applyView()};document.getElementById('pfZoomLabel').onclick=()=>{view.zoom=1;applyView()};document.getElementById('pfFit').onclick=()=>{if(!graph.nodes.length){view={x:80,y:60,zoom:1};applyView();return}const minX=Math.min(...graph.nodes.map(n=>Number(n.x)||0)),minY=Math.min(...graph.nodes.map(n=>Number(n.y)||0)),maxX=Math.max(...graph.nodes.map(n=>(Number(n.x)||0)+210)),maxY=Math.max(...graph.nodes.map(n=>(Number(n.y)||0)+110)),r=canvas.getBoundingClientRect();view.zoom=Math.max(.4,Math.min(1.2,Math.min((r.width-120)/(maxX-minX),(r.height-120)/(maxY-minY))));view.x=60-minX*view.zoom;view.y=60-minY*view.zoom;applyView()};
document.querySelectorAll('[data-flow-action]').forEach(b=>b.addEventListener('click',()=>document.getElementById('pfAction').value=b.dataset.flowAction));document.getElementById('pfForm').addEventListener('submit',e=>{if(!canWrite){e.preventDefault();return}graph.viewport={x:view.x,y:view.y,zoom:view.zoom};document.getElementById('pfGraphJson').value=JSON.stringify(graph)});
palette();render();renderInspector();window.addEventListener('resize',renderEdges);
})();
</script>
